(function() {
  const BASE64_YELLOW = "data:image/png;base64,";
  const BASE64_ROJO = "data:image/png;base64,";
  const BASE64_VERDE = "data:image/png;base64,";
  const BASE64_AZUL = "data:image/png;base64,";

  let scene, camera, renderer, controls;
  let gridsGroup;
  let autoRotate = true;
  let isGalleryMode = true;
  let animationFrameId = null;

  let meshes = [];
  let stackOrder = [0, 1, 2, 3]; // 0: Yellow (top), 1: Red, 2: Green, 3: Blue (bottom)
  let isAnimating = false;
  let animProgress = 0;
  let animMesh = null;
  let oldTopPos = new THREE.Vector3();
  let newBottomPos = new THREE.Vector3();

  let raycaster = new THREE.Raycaster();
  let mouse = new THREE.Vector2();
  let pointerDownPos = new THREE.Vector2();

  function getTargetPosition(stackPos) {
    // Slight offset down and left for sheets underneath to give a fanned stack look
    return new THREE.Vector3(
      -stackPos * 0.022,
      -stackPos * 0.022,
      -stackPos * 0.035
    );
  }

  function init() {
    const container = document.getElementById('canvas-cuadriculas3d');
    if (!container) return;

    container.innerHTML = '';

    scene = new THREE.Scene();
    
    // Camera
    camera = new THREE.PerspectiveCamera(45, container.clientWidth / container.clientHeight, 0.1, 10);
    camera.position.set(0, 0, 3.2);

    // Renderer
    renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    renderer.setPixelRatio(window.devicePixelRatio);
    renderer.setSize(container.clientWidth, container.clientHeight);
    container.appendChild(renderer.domElement);

    // Controls
    controls = new THREE.OrbitControls(camera, renderer.domElement);
    controls.enableDamping = true;
    controls.dampingFactor = 0.05;
    controls.enabled = false;
    controls.minDistance = 1.2;
    controls.maxDistance = 5.0;

    // Lights
    const ambientLight = new THREE.AmbientLight(0xffffff, 0.85);
    scene.add(ambientLight);

    const dirLight1 = new THREE.DirectionalLight(0xffffff, 0.55);
    dirLight1.position.set(2, 4, 5);
    scene.add(dirLight1);

    const dirLight2 = new THREE.DirectionalLight(0xffffff, 0.25);
    dirLight2.position.set(-2, -2, 2);
    scene.add(dirLight2);

    // Textures
    const loader = new THREE.TextureLoader();
    const texYellow = loader.load(BASE64_YELLOW);
    const texRojo = loader.load(BASE64_ROJO);
    const texVerde = loader.load(BASE64_VERDE);
    const texAzul = loader.load(BASE64_AZUL);

    [texYellow, texRojo, texVerde, texAzul].forEach(tex => {
      tex.anisotropy = 4;
      tex.minFilter = THREE.LinearFilter;
    });

    // Materials
    const sideMat = new THREE.MeshStandardMaterial({ color: 0x1b1d20, roughness: 0.8 });

    function createGridMesh(texture) {
      const frontMat = new THREE.MeshStandardMaterial({
        map: texture,
        roughness: 0.35,
        metalness: 0.05
      });
      return new THREE.Mesh(
        new THREE.BoxGeometry(1.2, 1.2, 0.02),
        [sideMat, sideMat, sideMat, sideMat, frontMat, sideMat]
      );
    }

    gridsGroup = new THREE.Group();

    // Create meshes
    const meshYellow = createGridMesh(texYellow);
    const meshRojo = createGridMesh(texRojo);
    const meshVerde = createGridMesh(texVerde);
    const meshAzul = createGridMesh(texAzul);

    meshes = [meshYellow, meshRojo, meshVerde, meshAzul];

    // Set initial positions in fanned stack
    for (let pos = 0; pos < 4; pos++) {
      const meshIdx = stackOrder[pos];
      meshes[meshIdx].position.copy(getTargetPosition(pos));
      gridsGroup.add(meshes[meshIdx]);
    }

    scene.add(gridsGroup);

    setupUI();
    
    // Event listeners registered on container div to bypass OrbitControls interception
    container.addEventListener('pointerdown', onPointerDown);
    container.addEventListener('pointerup', onPointerUp);

    autoRotate = true;
    isGalleryMode = true;
    animate();
  }

  function onPointerDown(event) {
    pointerDownPos.set(event.clientX, event.clientY);
  }

  function onPointerUp(event) {
    if (isGalleryMode || isAnimating) return;

    // Filter out mouse movements/dragging (camera rotation)
    const moveDistance = Math.hypot(event.clientX - pointerDownPos.x, event.clientY - pointerDownPos.y);
    if (moveDistance > 6) return;

    // Get click coordinates relative to the canvas
    const rect = renderer.domElement.getBoundingClientRect();
    mouse.x = ((event.clientX - rect.left) / rect.width) * 2 - 1;
    mouse.y = -((event.clientY - rect.top) / rect.height) * 2 + 1;

    raycaster.setFromCamera(mouse, camera);
    const intersects = raycaster.intersectObjects(meshes);

    if (intersects.length > 0) {
      // User clicked on the stack, start cycle transition
      startCycleAnimation();
    }
  }

  function startCycleAnimation() {
    isAnimating = true;
    animProgress = 0;
    
    // Top mesh in the stack
    animMesh = meshes[stackOrder[0]];
    oldTopPos.copy(animMesh.position);
    
    // Position 3 (bottom) in the next stack configuration
    newBottomPos.copy(getTargetPosition(3));
  }

  function setupUI() {
    const rotateBtn = document.getElementById('btn-cuadriculas3d-rotate');
    const topBtn = document.getElementById('btn-cuadriculas3d-top');
    const perspectiveBtn = document.getElementById('btn-cuadriculas3d-persp');

    if (rotateBtn) {
      rotateBtn.addEventListener('click', () => {
        autoRotate = !autoRotate;
        rotateBtn.classList.toggle('is-active', autoRotate);
      });
    }
    if (topBtn) {
      topBtn.addEventListener('click', () => {
        autoRotate = false;
        if (rotateBtn) rotateBtn.classList.remove('is-active');
        animateCamera(0, 0, 3.2);
        if (gridsGroup) gridsGroup.rotation.set(0, 0, 0);
      });
    }
    if (perspectiveBtn) {
      perspectiveBtn.addEventListener('click', () => {
        autoRotate = false;
        if (rotateBtn) rotateBtn.classList.remove('is-active');
        animateCamera(1.5, 0.8, 2.5);
      });
    }
  }

  let cameraAnim = {
    active: false,
    targetX: 0,
    targetY: 0,
    targetZ: 0,
    speed: 0.08
  };

  function animateCamera(x, y, z) {
    cameraAnim.targetX = x;
    cameraAnim.targetY = y;
    cameraAnim.targetZ = z;
    cameraAnim.active = true;
  }

  function setMode(isLarge) {
    autoRotate = !isLarge;
    isGalleryMode = !isLarge;
    if (controls) {
      controls.enabled = isLarge;
      if (!isLarge) {
        camera.position.set(0, 0, 3.2);
        controls.target.set(0, 0, 0);
        if (gridsGroup) gridsGroup.rotation.set(0, 0, 0);
        
        // Reset stack order and position instantly
        stackOrder = [0, 1, 2, 3];
        isAnimating = false;
        animMesh = null;
        for (let pos = 0; pos < 4; pos++) {
          const meshIdx = stackOrder[pos];
          meshes[meshIdx].position.copy(getTargetPosition(pos));
        }
      }
    }
    const rotateBtn = document.getElementById('btn-cuadriculas3d-rotate');
    if (rotateBtn) {
      rotateBtn.classList.toggle('is-active', autoRotate);
    }
  }

  function resize() {
    const container = document.getElementById('canvas-cuadriculas3d');
    if (!renderer || !camera || !container) return;
    camera.aspect = container.clientWidth / container.clientHeight;
    camera.updateProjectionMatrix();
    renderer.setSize(container.clientWidth, container.clientHeight);
  }

  function animate() {
    if (animationFrameId) {
      cancelAnimationFrame(animationFrameId);
    }
    
    function loop() {
      animationFrameId = requestAnimationFrame(loop);

      if (autoRotate && gridsGroup) {
        gridsGroup.rotation.y += 0.008;
      }

      if (isAnimating) {
        animProgress += 0.045; // Animation step speed

        if (animProgress < 0.5) {
          // Slide out to the right and lift in front
          const t = animProgress * 2;
          animMesh.position.x = oldTopPos.x + (1.4 - oldTopPos.x) * t;
          animMesh.position.y = oldTopPos.y + (0.1 - oldTopPos.y) * t;
          animMesh.position.z = oldTopPos.z + (0.18 - oldTopPos.z) * t;
        } else if (animProgress >= 0.5 && animProgress < 1.0) {
          // Perform reordering once at the half-way mark
          if (animProgress - 0.045 < 0.5) {
            const top = stackOrder.shift();
            stackOrder.push(top);
          }
          // Slide back in from the right, heading underneath the stack
          const t = (animProgress - 0.5) * 2;
          animMesh.position.x = 1.4 + (newBottomPos.x - 1.4) * t;
          animMesh.position.y = 0.1 + (newBottomPos.y - 0.1) * t;
          animMesh.position.z = 0.18 + (newBottomPos.z - 0.18) * t;
        } else {
          // Animation finished, enforce exact back of stack targets
          animProgress = 1.0;
          isAnimating = false;
          if (stackOrder[3] !== meshes.indexOf(animMesh)) {
            const top = stackOrder.shift();
            stackOrder.push(top);
          }
          animMesh = null;
        }

        // Interpolate the other meshes towards their new fanned offset positions
        for (let pos = 0; pos < 4; pos++) {
          const meshIdx = stackOrder[pos];
          if (meshes[meshIdx] !== animMesh) {
            const targetPos = getTargetPosition(pos);
            meshes[meshIdx].position.lerp(targetPos, 0.15);
          }
        }
      } else {
        // Standard lerping to target positions when idle
        for (let pos = 0; pos < 4; pos++) {
          const meshIdx = stackOrder[pos];
          const targetPos = getTargetPosition(pos);
          meshes[meshIdx].position.lerp(targetPos, 0.15);
        }
      }

      if (cameraAnim.active) {
        camera.position.x += (cameraAnim.targetX - camera.position.x) * cameraAnim.speed;
        camera.position.y += (cameraAnim.targetY - camera.position.y) * cameraAnim.speed;
        camera.position.z += (cameraAnim.targetZ - camera.position.z) * cameraAnim.speed;
        if (Math.abs(camera.position.x - cameraAnim.targetX) < 0.01 &&
            Math.abs(camera.position.y - cameraAnim.targetY) < 0.01 &&
            Math.abs(camera.position.z - cameraAnim.targetZ) < 0.01) {
          cameraAnim.active = false;
        }
      }

      if (controls && controls.enabled) {
        controls.update();
      }

      if (renderer && scene && camera) {
        renderer.render(scene, camera);
      }
    }
    loop();
  }

  function checkAndInit() {
    if (typeof THREE !== 'undefined' && THREE.OrbitControls) init();
    else setTimeout(checkAndInit, 50);
  }

  window.Cuadriculas3D = {
    init: function() {
      checkAndInit();
    },
    setMode,
    resize
  };
})();